import{_ as s,c as t,o as e,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Компактное восстановление: Автоматическое восстановление навыков | opencode-agent-skills","description":"Изучите механизм компактного восстановления в opencode-agent-skills. Автоматическое восстановление списка навыков после сжатия сессии, использование синтетических сообщений для сохранения доступности.","frontmatter":{"title":"Компактное восстановление: Автоматическое восстановление навыков | opencode-agent-skills","sidebarTitle":"Навыки не теряются после сжатия","subtitle":"Компактное восстановление: Автоматическое восстановление навыков","description":"Изучите механизм компактного восстановления в opencode-agent-skills. Автоматическое восстановление списка навыков после сжатия сессии, использование синтетических сообщений для сохранения доступности.","tags":["Управление контекстом","Сохранение сессий","Расширенные функции"],"prerequisite":["platforms-loading-skills-into-context"],"order":4},"headers":[],"relativePath":"ru/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md","filePath":"ru/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"}'),l={name:"ru/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"};function n(o,a,r,d,p,h){return e(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="механизм-восстановления-контекста-после-сжатия" tabindex="-1">Механизм восстановления контекста после сжатия <a class="header-anchor" href="#механизм-восстановления-контекста-после-сжатия" aria-label="Permalink to &quot;Механизм восстановления контекста после сжатия&quot;">​</a></h1><h2 id="что-вы-сможете-после-обучения" tabindex="-1">Что вы сможете после обучения <a class="header-anchor" href="#что-вы-сможете-после-обучения" aria-label="Permalink to &quot;Что вы сможете после обучения&quot;">​</a></h2><ul><li>Понимать, как плагин сохраняет доступность навыков после сжатия сессии</li><li>Знать условия запуска и процесс выполнения восстановления после сжатия</li><li>Уметь проверять, работает ли механизм восстановления</li><li>Понимать роль синтетических сообщений в механизме восстановления</li></ul><h2 id="текущая-проблема" tabindex="-1">Текущая проблема <a class="header-anchor" href="#текущая-проблема" aria-label="Permalink to &quot;Текущая проблема&quot;">​</a></h2><p>В длинных сессиях OpenCode выполняет <strong>сжатие контекста</strong> (Context Compaction) для экономии токенов. Сжатая сессия сохраняет только последние сообщения, а ранняя история (включая ранее внедрённое содержимое навыков) удаляется.</p><p>Это вызывает проблему: если содержимое навыков было сжато, ИИ больше не знает о доступных навыках и не может использовать загруженные навыки.</p><h2 id="когда-использовать-этот-метод" tabindex="-1">Когда использовать этот метод <a class="header-anchor" href="#когда-использовать-этот-метод" aria-label="Permalink to &quot;Когда использовать этот метод&quot;">​</a></h2><p>Механизм восстановления после сжатия работает <strong>автоматически</strong>, вам не нужно вмешиваться вручную. Но понимание его принципов поможет вам устранять неполадки в следующих сценариях:</p><ul><li>ИИ внезапно &quot;забыл&quot; навыки в длинной сессии</li><li>Нужно отладить доступность навыков после сжатия</li><li>Хотите понять стратегию управления сессиями в плагине</li></ul><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><h3 id="что-такое-сжатие-контекста" tabindex="-1">Что такое сжатие контекста? <a class="header-anchor" href="#что-такое-сжатие-контекста" aria-label="Permalink to &quot;Что такое сжатие контекста?&quot;">​</a></h3><p>Сессия OpenCode становится длиннее по мере увеличения количества сообщений. Когда потребление токенов приближается к лимиту, система автоматически выполняет <strong>сжатие контекста</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Начало сессии] → [Сообщение 1] → [Сообщение 2] → ... → [Сообщение 50]</span></span>
<span class="line"><span>                          ↑ Точка сжатия: сохраняются только последние 10 сообщений</span></span></code></pre></div><p>После сжатия ранние сообщения (включая содержимое внедрённых навыков) удаляются, ИИ видит только историю последних сообщений.</p><h3 id="как-работает-механизм-восстановления-после-сжатия" tabindex="-1">Как работает механизм восстановления после сжатия <a class="header-anchor" href="#как-работает-механизм-восстановления-после-сжатия" aria-label="Permalink to &quot;Как работает механизм восстановления после сжатия&quot;">​</a></h3><p>Плагин прослушивает событие <code>session.compacted</code>, и при обнаружении сжатия немедленно выполняет следующие операции восстановления:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Срабатывание сжатия сессии] --&gt; B[Событие session.compacted]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C{Включены Superpowers?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|Да| D[Повторное внедрение подсказки Superpowers]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|Нет| E[Пропуск Superpowers]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; F[Повторное внедрение списка навыков]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[Очистка записей загруженных навыков]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[Восстановление завершено]</span></span></code></pre></div><p><strong>Ключевые моменты</strong>:</p><ul><li>Восстановление происходит <strong>автоматически</strong>, без ручного запуска</li><li>Восстановленный список навыков содержит <strong>все найденные навыки</strong> (не только ранее загруженные)</li><li>Записи загруженных навыков очищаются, позволяя ИИ заново оценить, какие навыки нужны</li></ul><h3 id="роль-синтетических-сообщении" tabindex="-1">Роль синтетических сообщений <a class="header-anchor" href="#роль-синтетических-сообщении" aria-label="Permalink to &quot;Роль синтетических сообщений&quot;">​</a></h3><p>Плагин использует механизм <strong>Synthetic Message Injection</strong> (внедрение синтетических сообщений) для внедрения содержимого:</p><table tabindex="0"><thead><tr><th>Свойство</th><th>Значение</th><th>Значение</th></tr></thead><tbody><tr><td><code>noReply</code></td><td><code>true</code></td><td>ИИ не отвечает на внедрённое содержимое</td></tr><tr><td><code>synthetic</code></td><td><code>true</code></td><td>Помечено как сгенерированное системой содержимое, не учитывается в пользовательском вводе, не отображается в интерфейсе</td></tr></tbody></table><p>Это означает, что содержимое, внедрённое при восстановлении после сжатия:</p><ul><li>Полностью прозрачно для пользователя (не видно)</li><li>Не расходует квоту пользовательских сообщений</li><li>Но читается и понимается ИИ</li></ul><h2 id="🎒-подготовка" tabindex="-1">🎒 Подготовка <a class="header-anchor" href="#🎒-подготовка" aria-label="Permalink to &quot;🎒 Подготовка&quot;">​</a></h2><p>Для этого учебника требуется:</p><ul><li>Установленный плагин OpenCode Agent Skills</li><li>Понимание основ загрузки навыков</li><li>Длинная сессия для тестирования эффекта сжатия</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Дополнительная подготовка не требуется, механизм восстановления после сжатия — встроенная функция плагина.</p></div><h2 id="следуите-инструкциям-проверка-эффекта-восстановления-после-сжатия" tabindex="-1">Следуйте инструкциям: проверка эффекта восстановления после сжатия <a class="header-anchor" href="#следуите-инструкциям-проверка-эффекта-восстановления-после-сжатия" aria-label="Permalink to &quot;Следуйте инструкциям: проверка эффекта восстановления после сжатия&quot;">​</a></h2><h3 id="шаг-1-запустите-новую-сессию" tabindex="-1">Шаг 1: Запустите новую сессию <a class="header-anchor" href="#шаг-1-запустите-новую-сессию" aria-label="Permalink to &quot;Шаг 1: Запустите новую сессию&quot;">​</a></h3><p><strong>Зачем</strong> Проверить, нормально ли внедряется список навыков при инициализации сессии</p><p>Запустите новую сессию, введите любое сообщение:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Привет</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>: ИИ отвечает нормально, и в фоне автоматически внедряется список навыков (невидим для пользователя)</p><h3 id="шаг-2-загрузите-навык" tabindex="-1">Шаг 2: Загрузите навык <a class="header-anchor" href="#шаг-2-загрузите-навык" aria-label="Permalink to &quot;Шаг 2: Загрузите навык&quot;">​</a></h3><p><strong>Зачем</strong> Убедиться, что содержимое навыка внедрено в контекст</p><p>Вызовите инструмент <code>use_skill</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Используйте get_available_skills для просмотра доступных навыков, затем используйте use_skill для загрузки одного из навыков</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>: ИИ перечисляет доступные навыки, затем загружает выбранный вами навык</p><h3 id="шаг-3-инициируите-сжатие-контекста" tabindex="-1">Шаг 3: Инициируйте сжатие контекста <a class="header-anchor" href="#шаг-3-инициируите-сжатие-контекста" aria-label="Permalink to &quot;Шаг 3: Инициируйте сжатие контекста&quot;">​</a></h3><p><strong>Зачем</strong> Смоделировать сценарий длинной сессии, запустить механизм сжатия OpenCode</p><p>Продолжайте отправлять сообщения, имитируя длинный диалог:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Сообщение 1: Тестовое содержимое</span></span>
<span class="line"><span>Сообщение 2: Продолжение теста</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(Повторите отправку 20-30 сообщений)</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>:</p><ul><li>История сессии удлиняется с увеличением количества сообщений</li><li>При достижении определённой длины OpenCode автоматически выполняет сжатие</li><li>После сжатия ранние сообщения (включая внедрение навыков) удаляются</li></ul><h3 id="шаг-4-проверьте-эффект-восстановления" tabindex="-1">Шаг 4: Проверьте эффект восстановления <a class="header-anchor" href="#шаг-4-проверьте-эффект-восстановления" aria-label="Permalink to &quot;Шаг 4: Проверьте эффект восстановления&quot;">​</a></h3><p><strong>Зачем</strong> Убедиться, что после сжатия список навыков повторно внедряется</p><p>После сжатия попросите ИИ использовать навык:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Помогите мне использовать навык git-helper для создания новой ветки (предполагается, что у вас установлен навык git-helper)</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>:</p><ul><li>ИИ по-прежнему знает о доступных навыках (доказывает, что список навыков восстановлен)</li><li>ИИ может нормально загружать и использовать навыки (доказывает, что функциональность навыков не пострадала от сжатия)</li></ul><h3 id="шаг-5-проверьте-внедрение-синтетических-сообщении" tabindex="-1">Шаг 5: Проверьте внедрение синтетических сообщений <a class="header-anchor" href="#шаг-5-проверьте-внедрение-синтетических-сообщении" aria-label="Permalink to &quot;Шаг 5: Проверьте внедрение синтетических сообщений&quot;">​</a></h3><p><strong>Зачем</strong> Подтвердить, что механизм восстановления использует синтетические сообщения и не вмешивается в диалог</p><p>Если плагин поддерживает, можно проверить историю сообщений сессии (зависит от функциональности OpenCode):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Используйте инструменты отладки для просмотра истории сообщений сессии</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>:</p><ul><li>Сообщение с восстановленным списком навыков помечено как <code>synthetic: true</code></li><li>Эти сообщения не отображаются в обычном интерфейсе диалога</li></ul><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><p>После выполнения указанных шагов вы должны подтвердить:</p><ul><li>[ ] В длинной сессии ИИ по-прежнему имеет доступ к списку навыков</li><li>[ ] Функция загрузки навыков работает нормально после сжатия</li><li>[ ] Процесс восстановления полностью прозрачен для пользователя</li></ul><h2 id="предостережения" tabindex="-1">Предостережения <a class="header-anchor" href="#предостережения" aria-label="Permalink to &quot;Предостережения&quot;">​</a></h2><h3 id="проблема-1-после-сжатия-ии-говорит-не-наиден-навык" tabindex="-1">Проблема 1: После сжатия ИИ говорит &quot;не найден навык&quot; <a class="header-anchor" href="#проблема-1-после-сжатия-ии-говорит-не-наиден-навык" aria-label="Permalink to &quot;Проблема 1: После сжатия ИИ говорит &quot;не найден навык&quot;&quot;">​</a></h3><p><strong>Возможные причины</strong>:</p><ul><li>Плагин неправильно слушает событие <code>session.compacted</code></li><li>Путь к каталогу навыков изменился</li></ul><p><strong>Решение</strong>:</p><ol><li><p><strong>Проверьте, запускается ли событие сжатия</strong></p><ul><li>Выполните шаги 3 и 4 из раздела &quot;Следуйте инструкциям&quot;, подтвердите, что после сжатия ИИ по-прежнему имеет доступ к списку навыков</li><li>Если ИИ может нормально использовать навыки, механизм восстановления после сжатия работает нормально</li></ul></li><li><p><strong>Проверьте, правильно ли загружен плагин</strong></p><ul><li>Перезапустите OpenCode</li><li>После запуска новой сессии попросите ИИ перечислить доступные навыки (<code>get_available_skills</code>)</li><li>Если виден список навыков, значит плагин загружен правильно</li></ul></li></ol><h3 id="проблема-2-восстановленныи-список-навыков-пуст" tabindex="-1">Проблема 2: Восстановленный список навыков пуст <a class="header-anchor" href="#проблема-2-восстановленныи-список-навыков-пуст" aria-label="Permalink to &quot;Проблема 2: Восстановленный список навыков пуст&quot;">​</a></h3><p><strong>Возможные причины</strong>:</p><ul><li>В пути обнаружения навыков нет навыков</li><li>Ошибка в формате файла навыков</li></ul><p><strong>Решение</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Вручную запросить доступные навыки</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Используйте</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get_available_skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> для</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> просмотра</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> списка</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> навыков</span></span></code></pre></div><p>Если возвращается пустой список, проверьте каталог навыков и формат файлов.</p><h3 id="проблема-3-после-сжатия-теряется-состояние-загруженных-навыков" tabindex="-1">Проблема 3: После сжатия теряется состояние загруженных навыков <a class="header-anchor" href="#проблема-3-после-сжатия-теряется-состояние-загруженных-навыков" aria-label="Permalink to &quot;Проблема 3: После сжатия теряется состояние загруженных навыков&quot;">​</a></h3><p><strong>Это ожидаемое поведение</strong>, не ошибка. Механизм восстановления очищает запись <code>loadedSkillsPerSession</code>, позволяя ИИ заново оценить, какие навыки нужны.</p><p><strong>Решение</strong>: ИИ автоматически определит, нужно ли повторно загружать навыки, на основе контекста, без ручного вмешательства.</p><h2 id="итог-урока" tabindex="-1">Итог урока <a class="header-anchor" href="#итог-урока" aria-label="Permalink to &quot;Итог урока&quot;">​</a></h2><p>Механизм восстановления после сжатия обеспечивает доступность навыков в длинных сессиях следующими способами:</p><ol><li><strong>Прослушивание события сжатия</strong>: Автоматическое обнаружение события <code>session.compacted</code></li><li><strong>Повторное внедрение списка навыков</strong>: Внедрение всех навыков с использованием тега <code>&lt;available-skills&gt;</code></li><li><strong>Опциональное восстановление Superpowers</strong>: При включении одновременно восстанавливается подсказка Superpowers</li><li><strong>Использование синтетических сообщений</strong>: Процесс восстановления прозрачен для пользователя, не влияет на диалог</li><li><strong>Сброс записей загруженных навыков</strong>: Очистка набора загруженных навыков, позволяющая повторную оценку</li></ol><p>Этот механизм обеспечивает:</p><ul><li>Навыки всегда доступны в длинных сессиях</li><li>Процесс восстановления автоматизирован и незаметен</li><li>ИИ может решать, какие навыки использовать, на основе актуального контекста</li></ul><h2 id="предпросмотр-следующего-урока" tabindex="-1">Предпросмотр следующего урока <a class="header-anchor" href="#предпросмотр-следующего-урока" aria-label="Permalink to &quot;Предпросмотр следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../../faq/troubleshooting/">Устранение неполадок</a></strong>.</p><p>Вы узнаете:</p><ul><li>Методы обработки распространённых ошибок и исключений</li><li>Техники устранения неполадок, связанные с восстановлением после сжатия</li><li>Решения других проблем использования</li></ul></blockquote><hr><h2 id="приложение-ссылка-на-исходныи-код" tabindex="-1">Приложение: Ссылка на исходный код <a class="header-anchor" href="#приложение-ссылка-на-исходныи-код" aria-label="Permalink to &quot;Приложение: Ссылка на исходный код&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы раскрыть расположение исходного кода</strong></summary><blockquote><p>Время обновления: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Номер строки</th></tr></thead><tbody><tr><td>Прослушивание события сжатия</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L157" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-157</td></tr><tr><td>Инициализация при первом сообщении</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L70-L105" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>70-105</td></tr><tr><td>Внедрение списка навыков</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L345-L370" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>345-370</td></tr><tr><td>Внедрение синтетических сообщений</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>Управление состоянием сессии</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L25-L35" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>25-35</td></tr></tbody></table><p><strong>Ключевые переменные</strong>:</p><ul><li><code>setupCompleteSessions: Set&lt;string&gt;</code> — Записывает идентификаторы сессий, завершивших инициализацию</li><li><code>loadedSkillsPerSession: Map&lt;string, Set&lt;string&gt;&gt;</code> — Записывает имена загруженных навыков для каждой сессии</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>injectSkillsList()</code> — Внедряет список доступных навыков в сессию</li><li><code>injectSyntheticContent()</code> — Использует синтетические сообщения для внедрения содержимого</li><li><code>getSessionContext()</code> — Получает информацию о модели и агенте сессии</li></ul></details>`,85)])])}const u=s(l,[["render",n]]);export{g as __pageData,u as default};
